#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define Rep(a,b,c) for(c=(a);c<=(b);++c)
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Max(int x,int y){return x>y?x:y;}
inline int Min(int x,int y){return x<y?x:y;}
const int N=1e6+10,INF=0x3f3f3f3f;
struct Node{int l,r,sm,mx,mn,tag1,tag2;}t[N<<2];
int n,m,Q,Sm,Mn,Mx,rw,Rt[21],cnt;
inline void Out(){printf("%d %d %d\n",Sm,Mn,Mx);}
inline void update(int cur)
{
    int ls=t[cur].l,rs=t[cur].r;t[cur].sm=t[ls].sm+t[rs].sm;
    t[cur].mn=Min(t[ls].mn,t[rs].mn);t[cur].mx=Max(t[ls].mx,t[rs].mx);
}
inline void pushdown(int cur,int l,int r)
{
    if(t[cur].tag2!=-1)
    {
        int ls=t[cur].l,rs=t[cur].r,w=t[cur].tag2,mid=(l+r)>>1;t[cur].tag2=-1;
        t[ls].tag1=t[rs].tag1=0;t[ls].sm=(mid-l+1)*w;t[rs].sm=(r-mid)*w;
        t[ls].tag2=t[rs].tag2=t[ls].mn=t[ls].mx=t[rs].mn=t[rs].mx=w;
    }
    if(t[cur].tag1)
    {
        int ls=t[cur].l,rs=t[cur].r,w=t[cur].tag1,mid=(l+r)>>1;t[cur].tag1=0;
        t[ls].sm+=(mid-l+1)*w;t[rs].sm+=(r-mid)*w;t[ls].tag1+=w;t[rs].tag1+=w;
        t[ls].mn+=w;t[rs].mn+=w;t[ls].mx+=w;t[rs].mx+=w;return;
    }
}
inline void build(int &cur,int l=1,int r=m)
{
    t[cur=++cnt].tag2=-1;t[cur].sm=t[cur].mn=t[cur].mx=t[cur].tag1=0;
    if(l==r)return;int mid=(l+r)>>1;build(t[cur].l,l,mid);build(t[cur].r,mid+1,r);
}
inline void add(int ql,int qr,int val,int l=1,int r=m,int cur=Rt[rw])
{
    if(ql<=l&&r<=qr)
    {
        t[cur].sm+=(r-l+1)*val;
        t[cur].mx+=val;t[cur].mn+=val;
        t[cur].tag1+=val;return;
    }
    pushdown(cur,l,r);int mid=(l+r)>>1;
    if(ql<=mid)add(ql,qr,val,l,mid,t[cur].l);
    if(qr>mid)add(ql,qr,val,mid+1,r,t[cur].r);
    update(cur);return;
}
inline void cpy(int ql,int qr,int val,int l=1,int r=m,int cur=Rt[rw])
{
    if(ql<=l&&r<=qr)
    {
        t[cur].tag2=t[cur].mn=t[cur].mx=val;
        t[cur].tag1=0;t[cur].sm=(r-l+1)*val;return;
    }
    pushdown(cur,l,r);int mid=(l+r)>>1;
    if(ql<=mid)cpy(ql,qr,val,l,mid,t[cur].l);
    if(qr>mid)cpy(ql,qr,val,mid+1,r,t[cur].r);
    update(cur);return;
}
inline void qry(int ql,int qr,int l=1,int r=m,int cur=Rt[rw])
{
    if(ql<=l&&r<=qr)
    {
        Mn=Min(Mn,t[cur].mn);Mx=Max(Mx,t[cur].mx);
        Sm+=t[cur].sm;return;
    }
    pushdown(cur,l,r);int mid=(l+r)>>1;
    if(ql<=mid)qry(ql,qr,l,mid,t[cur].l);
    if(qr>mid)qry(ql,qr,mid+1,r,t[cur].r);
    update(cur);return;
}
inline void Solve()
{
    cnt=0;Rep(1,n,rw)build(Rt[rw]);
    while(Q--)
    {
        short opt=read();
        int x1=read(),y1=read(),x2=read(),y2=read(),w;
        switch(opt)
        {
            case 1: w=read();Rep(x1,x2,rw)add(y1,y2,w);break;
            case 2: w=read();Rep(x1,x2,rw)cpy(y1,y2,w);break;
            case 3: Mn=INF;Mx=Sm=0;Rep(x1,x2,rw)qry(y1,y2);Out();break;
        }
    }
}
int main()
{
    
    while(scanf("%d",&n)!=EOF){m=read();Q=read();Solve();}
    return 0;
}
